import React, { useState, useMemo } from 'react';

const TableComponent = () => {
    const [records, setRecords] = useState([
        { id: 1, name: 'adam', age: 25 },
        { id: 2, name: 'james', age: 30 },
        { id: 3, name: 'nick', age: 28 },
        { id: 4, name: 'john', age: 29 }
    ]);
    const [filter, setFilter] = useState('');
    const [sortField, setSortField] = useState('name');
    const [sortOrder, setSortOrder] = useState('asc');

    const filteredRecords = useMemo(() => {
        const filtered = records.filter(record => 
            record.name.toLowerCase().includes(filter.toLowerCase())
        );
        return filtered;
    }, [records, filter]);

    const sortedRecords = useMemo(() => {
        return filteredRecords.sort((a, b) => {
            if (sortOrder === 'asc') {
                return a[sortField].toLowerCase() > b[sortField].toLowerCase() ? 1 : -1;
            } else {
                return a[sortField].toLowerCase() < b[sortField].toLowerCase() ? 1 : -1;
            }
        });
    }, [filteredRecords, sortField, sortOrder, filter]);

    const handleSort = (field) => {
        setSortField(field);
        setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc');
    };

    const handleFilter = (e) => {
        setFilter(e.target.value);
    };

    return (
        <div>
            <div>
                <input
                    type="text"
                    placeholder="Filter by name..."
                    value={filter}
                    onChange={handleFilter}
                />
            </div>
            <table>
                <thead>
                    <tr>
                        <th onClick={() => handleSort('id')}>id</th>
                        <th onClick={() => handleSort('name')}>name</th>
                        <th onClick={() => handleSort('age')}>age</th>
                    </tr>
                </thead>
                <tbody>
                    {sortedRecords.map(record => (
                        <tr key={record.id}>
                            <td>{record.id}</td>
                            <td>{record.name}</td>
                            <td>{record.age}</td>
                        </tr>
                    ))}
                </tbody>
            </
